import{c as h,S as i,j as n,m as t}from"./chunks/framework.8aa1YH_s.js";const k=JSON.parse('{"title":"Câu hỏi thường gặp (FAQ)","description":"","frontmatter":{},"headers":[],"relativePath":"faq.md","filePath":"faq.md","lastUpdated":0}'),o={name:"faq.md"};function l(e,a,c,r,g,u){return i(),n("div",null,[...a[0]||(a[0]=[t('<h1 id="cau-hoi-thuong-gap-faq" tabindex="-1">Câu hỏi thường gặp (FAQ) <a class="header-anchor" href="#cau-hoi-thuong-gap-faq" aria-label="Permalink to “Câu hỏi thường gặp (FAQ)”">​</a></h1><p>Tổng hợp các câu hỏi phổ biến nhất từ học viên, giáo viên và quản trị viên.</p><nav class="table-of-contents"><ul><li><a href="#i-tai-khoan-đang-nhap">I. Tài khoản &amp; Đăng nhập</a><ul><li><a href="#toi-quen-mat-khau-lam-sao">Tôi quên mật khẩu, làm sao?</a></li><li><a href="#toi-khong-nhan-đuoc-otp-đang-ky">Tôi không nhận được OTP đăng ký?</a></li><li><a href="#toi-co-the-đang-nhap-tren-nhieu-thiet-bi-cung-luc-khong">Tôi có thể đăng nhập trên nhiều thiết bị cùng lúc không?</a></li><li><a href="#toi-muon-đoi-so-đien-thoai-email">Tôi muốn đổi số điện thoại / email?</a></li><li><a href="#tai-khoan-toi-bi-khoa-lam-sao-mo-lai">Tài khoản tôi bị khóa, làm sao mở lại?</a></li></ul></li><li><a href="#ii-mua-thanh-toan-khoa-hoc">II. Mua &amp; Thanh toán khóa học</a><ul><li><a href="#toi-đa-chuyen-khoan-nhung-chua-thay-mo-khoa">Tôi đã chuyển khoản nhưng chưa thấy mở khóa?</a></li><li><a href="#cong-thanh-toan-bao-loi">Cổng thanh toán báo lỗi?</a></li><li><a href="#toi-nhap-ma-khuyen-mai-nhung-khong-giam-gia">Tôi nhập mã khuyến mãi nhưng không giảm giá?</a></li><li><a href="#khoa-co-hoan-tien-đuoc-khong">Khóa có hoàn tiền được không?</a></li><li><a href="#toi-mua-nham-khoa">Tôi mua nhầm khóa?</a></li><li><a href="#toi-muon-xuat-hoa-đon-vat-cho-cong-ty">Tôi muốn xuất hóa đơn VAT cho công ty?</a></li></ul></li><li><a href="#iii-hoc-khoa-hoc">III. Học khóa học</a><ul><li><a href="#toi-đa-mua-khoa-nhung-khong-thay">Tôi đã mua khóa nhưng không thấy?</a></li><li><a href="#bai-giang-video-bi-giat-lag">Bài giảng video bị giật / lag?</a></li><li><a href="#toi-khong-xem-đuoc-video">Tôi không xem được video?</a></li><li><a href="#tien-đo-hoc-bi-mat">Tiến độ học bị mất?</a></li><li><a href="#toi-khong-mo-đuoc-chuyen-đe-tiep-theo">Tôi không mở được chuyên đề tiếp theo?</a></li><li><a href="#khoa-cua-toi-het-han">Khóa của tôi hết hạn?</a></li></ul></li><li><a href="#iv-lam-bai-thi-kiem-tra">IV. Làm bài thi / kiểm tra</a><ul><li><a href="#toi-can-lam-gi-truoc-khi-vao-thi-online">Tôi cần làm gì trước khi vào thi online?</a></li><li><a href="#toi-vo-tinh-tai-lai-trang-khi-đang-thi">Tôi vô tình tải lại trang khi đang thi?</a></li><li><a href="#het-gio-tu-nop-toi-chua-kip-lam-het">Hết giờ tự nộp - tôi chưa kịp làm hết?</a></li><li><a href="#toi-khong-đong-y-đap-an-cua-he-thong">Tôi không đồng ý đáp án của hệ thống?</a></li><li><a href="#toi-muon-lam-lai-bai-đa-lam">Tôi muốn làm lại bài đã làm?</a></li><li><a href="#bao-lau-thi-cham-xong-bai">Bao lâu thì chấm xong bài?</a></li></ul></li><li><a href="#v-ky-thi-cu-the">V. Kỳ thi cụ thể</a><ul><li><a href="#đe-hsa-mau-co-giong-đe-thi-that-khong">Đề HSA mẫu có giống đề thi thật không?</a></li><li><a href="#đe-tsa-co-dung-may-tinh-cam-tay-khong">Đề TSA có dùng máy tính cầm tay không?</a></li><li><a href="#đe-tnthpt-tren-he-thong-co-3-phan-tn-đung-sai-tra-loi-ngan">Đề TNTHPT trên hệ thống có 3 phần (TN/Đúng-Sai/Trả lời ngắn)?</a></li><li><a href="#toi-nen-lam-thi-thu-bao-nhieu-lan-truoc-ky-thi-that">Tôi nên làm thi thử bao nhiêu lần trước kỳ thi thật?</a></li></ul></li><li><a href="#vi-hoi-đap-voi-giao-vien">VI. Hỏi đáp với giáo viên</a><ul><li><a href="#bao-lau-giao-vien-tra-loi">Bao lâu giáo viên trả lời?</a></li><li><a href="#cau-hoi-cua-toi-co-cong-khai-khong">Câu hỏi của tôi có công khai không?</a></li></ul></li><li><a href="#vii-giao-vien">VII. Giáo viên</a><ul><li><a href="#toi-la-giao-vien-lam-sao-co-tai-khoan">Tôi là giáo viên, làm sao có tài khoản?</a></li><li><a href="#toi-quen-mat-khau-giao-vien">Tôi quên mật khẩu giáo viên?</a></li><li><a href="#toi-co-the-tao-khoa-hoc-moi-khong">Tôi có thể tạo khóa học mới không?</a></li><li><a href="#hoc-vien-bao-điem-sai-lam-sao">Học viên báo điểm sai, làm sao?</a></li></ul></li><li><a href="#viii-quan-tri-vien">VIII. Quản trị viên</a><ul><li><a href="#cau-hinh-he-thong-lan-đau-nen-bat-đau-tu-đau">Cấu hình hệ thống lần đầu nên bắt đầu từ đâu?</a></li><li><a href="#cap-quyen-cho-nhan-vien-the-nao">Cấp quyền cho nhân viên thế nào?</a></li><li><a href="#xoa-khoa-hoc-co-anh-huong-hoc-vien-khong">Xóa khóa học có ảnh hưởng học viên không?</a></li><li><a href="#toi-muon-backup-du-lieu-truoc-khi-sua-lon">Tôi muốn backup dữ liệu trước khi sửa lớn?</a></li></ul></li><li><a href="#ix-loi-ky-thuat-chung">IX. Lỗi kỹ thuật chung</a><ul><li><a href="#trang-trang-khong-load">Trang trắng / không load?</a></li><li><a href="#toi-nhan-thong-bao-phien-đang-nhap-đa-het-han">Tôi nhận thông báo &quot;Phiên đăng nhập đã hết hạn&quot;?</a></li><li><a href="#he-thong-cham-vao-gio-cao-điem">Hệ thống chậm vào giờ cao điểm?</a></li><li><a href="#toi-muon-bao-loi-moi">Tôi muốn báo lỗi mới?</a></li></ul></li><li><a href="#van-can-ho-tro">Vẫn cần hỗ trợ?</a></li></ul></nav><h2 id="i-tai-khoan-đang-nhap" tabindex="-1">I. Tài khoản &amp; Đăng nhập <a class="header-anchor" href="#i-tai-khoan-đang-nhap" aria-label="Permalink to “I. Tài khoản &amp; Đăng nhập”">​</a></h2><h3 id="toi-quen-mat-khau-lam-sao" tabindex="-1">Tôi quên mật khẩu, làm sao? <a class="header-anchor" href="#toi-quen-mat-khau-lam-sao" aria-label="Permalink to “Tôi quên mật khẩu, làm sao?”">​</a></h3><p>Tại trang đăng nhập, bấm <strong>Quên mật khẩu?</strong> → nhập SĐT/email đã đăng ký → nhập OTP → đặt mật khẩu mới. Xem chi tiết: <a href="/hoc-vien/dang-ky-dang-nhap">Đăng ký &amp; Đăng nhập</a>.</p><h3 id="toi-khong-nhan-đuoc-otp-đang-ky" tabindex="-1">Tôi không nhận được OTP đăng ký? <a class="header-anchor" href="#toi-khong-nhan-đuoc-otp-đang-ky" aria-label="Permalink to “Tôi không nhận được OTP đăng ký?”">​</a></h3><ul><li>Kiểm tra số điện thoại / email nhập đúng chưa.</li><li>Đợi 60s rồi bấm <strong>Gửi lại</strong>.</li><li>Kiểm tra hộp thư rác.</li><li>Thử số điện thoại / email khác.</li></ul><h3 id="toi-co-the-đang-nhap-tren-nhieu-thiet-bi-cung-luc-khong" tabindex="-1">Tôi có thể đăng nhập trên nhiều thiết bị cùng lúc không? <a class="header-anchor" href="#toi-co-the-đang-nhap-tren-nhieu-thiet-bi-cung-luc-khong" aria-label="Permalink to “Tôi có thể đăng nhập trên nhiều thiết bị cùng lúc không?”">​</a></h3><p>Mặc định <strong>chỉ 1-2 phiên đồng thời</strong>. Đăng nhập trên thiết bị mới có thể đẩy thiết bị cũ ra. Xem <a href="/hoc-vien/ho-so-ca-nhan">Hồ sơ → Thiết bị đăng nhập</a>.</p><h3 id="toi-muon-đoi-so-đien-thoai-email" tabindex="-1">Tôi muốn đổi số điện thoại / email? <a class="header-anchor" href="#toi-muon-đoi-so-đien-thoai-email" aria-label="Permalink to “Tôi muốn đổi số điện thoại / email?”">​</a></h3><p>Vào Hồ sơ cá nhân → sửa thông tin → xác thực OTP. Nếu không tự đổi được, liên hệ trung tâm.</p><h3 id="tai-khoan-toi-bi-khoa-lam-sao-mo-lai" tabindex="-1">Tài khoản tôi bị khóa, làm sao mở lại? <a class="header-anchor" href="#tai-khoan-toi-bi-khoa-lam-sao-mo-lai" aria-label="Permalink to “Tài khoản tôi bị khóa, làm sao mở lại?”">​</a></h3><p>Liên hệ Admin/CSKH. Cung cấp giấy tờ xác minh nếu được yêu cầu.</p><h2 id="ii-mua-thanh-toan-khoa-hoc" tabindex="-1">II. Mua &amp; Thanh toán khóa học <a class="header-anchor" href="#ii-mua-thanh-toan-khoa-hoc" aria-label="Permalink to “II. Mua &amp; Thanh toán khóa học”">​</a></h2><h3 id="toi-đa-chuyen-khoan-nhung-chua-thay-mo-khoa" tabindex="-1">Tôi đã chuyển khoản nhưng chưa thấy mở khóa? <a class="header-anchor" href="#toi-đa-chuyen-khoan-nhung-chua-thay-mo-khoa" aria-label="Permalink to “Tôi đã chuyển khoản nhưng chưa thấy mở khóa?”">​</a></h3><ul><li>Trong giờ hành chính: trung tâm xác nhận trong 1-24h.</li><li>Ngoài giờ: đợi sáng hôm sau.</li><li>Nếu chậm hơn 24h trong giờ hành chính → liên hệ hotline kèm ảnh biên lai.</li></ul><h3 id="cong-thanh-toan-bao-loi" tabindex="-1">Cổng thanh toán báo lỗi? <a class="header-anchor" href="#cong-thanh-toan-bao-loi" aria-label="Permalink to “Cổng thanh toán báo lỗi?”">​</a></h3><p>Thử lại sau vài phút hoặc đổi phương thức (VNPay → Momo → chuyển khoản). Xem <a href="/hoc-vien/gio-hang-thanh-toan">Giỏ hàng &amp; Thanh toán</a>.</p><h3 id="toi-nhap-ma-khuyen-mai-nhung-khong-giam-gia" tabindex="-1">Tôi nhập mã khuyến mãi nhưng không giảm giá? <a class="header-anchor" href="#toi-nhap-ma-khuyen-mai-nhung-khong-giam-gia" aria-label="Permalink to “Tôi nhập mã khuyến mãi nhưng không giảm giá?”">​</a></h3><p>Kiểm tra: mã còn hạn? Đúng khóa áp dụng? Đơn đạt giá tối thiểu? Bạn chưa dùng mã này trước đó?</p><h3 id="khoa-co-hoan-tien-đuoc-khong" tabindex="-1">Khóa có hoàn tiền được không? <a class="header-anchor" href="#khoa-co-hoan-tien-đuoc-khong" aria-label="Permalink to “Khóa có hoàn tiền được không?”">​</a></h3><p>Tùy chính sách trung tâm. Thường có thời gian hoàn tiền (7-14 ngày đầu) nếu chưa học quá X%. Liên hệ trung tâm.</p><h3 id="toi-mua-nham-khoa" tabindex="-1">Tôi mua nhầm khóa? <a class="header-anchor" href="#toi-mua-nham-khoa" aria-label="Permalink to “Tôi mua nhầm khóa?”">​</a></h3><p>Liên hệ trung tâm sớm nhất - nếu chưa học có thể đổi sang khóa khác.</p><h3 id="toi-muon-xuat-hoa-đon-vat-cho-cong-ty" tabindex="-1">Tôi muốn xuất hóa đơn VAT cho công ty? <a class="header-anchor" href="#toi-muon-xuat-hoa-đon-vat-cho-cong-ty" aria-label="Permalink to “Tôi muốn xuất hóa đơn VAT cho công ty?”">​</a></h3><p>Hệ thống cấp <strong>biên nhận điện tử</strong> mặc định. VAT đỏ cần liên hệ kế toán trung tâm.</p><h2 id="iii-hoc-khoa-hoc" tabindex="-1">III. Học khóa học <a class="header-anchor" href="#iii-hoc-khoa-hoc" aria-label="Permalink to “III. Học khóa học”">​</a></h2><h3 id="toi-đa-mua-khoa-nhung-khong-thay" tabindex="-1">Tôi đã mua khóa nhưng không thấy? <a class="header-anchor" href="#toi-đa-mua-khoa-nhung-khong-thay" aria-label="Permalink to “Tôi đã mua khóa nhưng không thấy?”">​</a></h3><p>Kiểm tra <a href="/hoc-vien/ho-so-ca-nhan#hoa-đon">Hóa đơn của tôi</a>. Có thể giao dịch chưa hoàn tất.</p><h3 id="bai-giang-video-bi-giat-lag" tabindex="-1">Bài giảng video bị giật / lag? <a class="header-anchor" href="#bai-giang-video-bi-giat-lag" aria-label="Permalink to “Bài giảng video bị giật / lag?”">​</a></h3><ul><li>Đổi chất lượng video xuống 480p/720p.</li><li>Kiểm tra tốc độ Internet (cần ≥ 5 Mbps cho HD).</li><li>Tắt các app/tab nặng.</li><li>Thử trình duyệt khác.</li></ul><h3 id="toi-khong-xem-đuoc-video" tabindex="-1">Tôi không xem được video? <a class="header-anchor" href="#toi-khong-xem-đuoc-video" aria-label="Permalink to “Tôi không xem được video?”">​</a></h3><ul><li>Cập nhật trình duyệt.</li><li>Tắt extension chặn quảng cáo.</li><li>Đảm bảo JavaScript bật.</li><li>Thử trình duyệt khác (Chrome khuyến nghị).</li></ul><h3 id="tien-đo-hoc-bi-mat" tabindex="-1">Tiến độ học bị mất? <a class="header-anchor" href="#tien-đo-hoc-bi-mat" aria-label="Permalink to “Tiến độ học bị mất?”">​</a></h3><p>Đảm bảo đăng nhập đúng tài khoản. Nếu vẫn mất, báo Hỏi đáp.</p><h3 id="toi-khong-mo-đuoc-chuyen-đe-tiep-theo" tabindex="-1">Tôi không mở được chuyên đề tiếp theo? <a class="header-anchor" href="#toi-khong-mo-đuoc-chuyen-đe-tiep-theo" aria-label="Permalink to “Tôi không mở được chuyên đề tiếp theo?”">​</a></h3><p>Có thể chuyên đề trước yêu cầu <strong>hoàn thành / đạt điểm tối thiểu</strong> bài kiểm tra. Quay lại làm.</p><h3 id="khoa-cua-toi-het-han" tabindex="-1">Khóa của tôi hết hạn? <a class="header-anchor" href="#khoa-cua-toi-het-han" aria-label="Permalink to “Khóa của tôi hết hạn?”">​</a></h3><p>Vào <strong>Khóa học của tôi</strong> → bấm <strong>Gia hạn</strong>. Hoặc liên hệ trung tâm.</p><h2 id="iv-lam-bai-thi-kiem-tra" tabindex="-1">IV. Làm bài thi / kiểm tra <a class="header-anchor" href="#iv-lam-bai-thi-kiem-tra" aria-label="Permalink to “IV. Làm bài thi / kiểm tra”">​</a></h2><h3 id="toi-can-lam-gi-truoc-khi-vao-thi-online" tabindex="-1">Tôi cần làm gì trước khi vào thi online? <a class="header-anchor" href="#toi-can-lam-gi-truoc-khi-vao-thi-online" aria-label="Permalink to “Tôi cần làm gì trước khi vào thi online?”">​</a></h3><ul><li>Internet ổn định</li><li>Máy đủ pin / cắm sạc</li><li>Đóng app không cần thiết</li><li>Nơi yên tĩnh, không bị làm phiền</li><li>Có giấy nháp + bút (+ máy tính cầm tay nếu được phép)</li></ul><h3 id="toi-vo-tinh-tai-lai-trang-khi-đang-thi" tabindex="-1">Tôi vô tình tải lại trang khi đang thi? <a class="header-anchor" href="#toi-vo-tinh-tai-lai-trang-khi-đang-thi" aria-label="Permalink to “Tôi vô tình tải lại trang khi đang thi?”">​</a></h3><p>Hệ thống thường lưu nháp - đăng nhập lại và vào tiếp bài. Đồng hồ tiếp tục chạy.</p><h3 id="het-gio-tu-nop-toi-chua-kip-lam-het" tabindex="-1">Hết giờ tự nộp - tôi chưa kịp làm hết? <a class="header-anchor" href="#het-gio-tu-nop-toi-chua-kip-lam-het" aria-label="Permalink to “Hết giờ tự nộp - tôi chưa kịp làm hết?”">​</a></h3><p>Câu chưa làm tính 0 điểm. <strong>Lần sau hãy &quot;tô đại&quot; còn hơn bỏ trống</strong> với câu trắc nghiệm.</p><h3 id="toi-khong-đong-y-đap-an-cua-he-thong" tabindex="-1">Tôi không đồng ý đáp án của hệ thống? <a class="header-anchor" href="#toi-khong-đong-y-đap-an-cua-he-thong" aria-label="Permalink to “Tôi không đồng ý đáp án của hệ thống?”">​</a></h3><p>Vào <a href="/hoc-vien/xem-lai-bai-thi">Xem lại bài thi</a> → câu đó → bấm <strong>Hỏi giáo viên</strong> kèm giải thích. Nếu giáo viên xác nhận đề sai, sẽ chỉnh điểm.</p><h3 id="toi-muon-lam-lai-bai-đa-lam" tabindex="-1">Tôi muốn làm lại bài đã làm? <a class="header-anchor" href="#toi-muon-lam-lai-bai-đa-lam" aria-label="Permalink to “Tôi muốn làm lại bài đã làm?”">​</a></h3><p>Tùy đề có cho phép không. Xem ở trang xem trước (Số lần làm còn lại). Một số đề chỉ làm 1 lần.</p><h3 id="bao-lau-thi-cham-xong-bai" tabindex="-1">Bao lâu thì chấm xong bài? <a class="header-anchor" href="#bao-lau-thi-cham-xong-bai" aria-label="Permalink to “Bao lâu thì chấm xong bài?”">​</a></h3><ul><li>Bài 100% trắc nghiệm: <strong>vài giây</strong> sau khi nộp.</li><li>Bài có tự luận / cần chấm tay: <strong>1-3 ngày làm việc</strong>.</li></ul><h2 id="v-ky-thi-cu-the" tabindex="-1">V. Kỳ thi cụ thể <a class="header-anchor" href="#v-ky-thi-cu-the" aria-label="Permalink to “V. Kỳ thi cụ thể”">​</a></h2><h3 id="đe-hsa-mau-co-giong-đe-thi-that-khong" tabindex="-1">Đề HSA mẫu có giống đề thi thật không? <a class="header-anchor" href="#đe-hsa-mau-co-giong-đe-thi-that-khong" aria-label="Permalink to “Đề HSA mẫu có giống đề thi thật không?”">​</a></h3><p>Bám sát cấu trúc HSA của ĐHQG Hà Nội: 3 phần × 50 câu, 195 phút tổng. Xem <a href="/hoc-vien/thi-dgnl-hsa">Thi ĐGNL (HSA)</a>.</p><h3 id="đe-tsa-co-dung-may-tinh-cam-tay-khong" tabindex="-1">Đề TSA có dùng máy tính cầm tay không? <a class="header-anchor" href="#đe-tsa-co-dung-may-tinh-cam-tay-khong" aria-label="Permalink to “Đề TSA có dùng máy tính cầm tay không?”">​</a></h3><p>Kỳ thi thật cho phép. Đề mẫu nên luyện trong điều kiện tương tự. Xem <a href="/hoc-vien/thi-dgtd-tsa">Thi ĐGTD (TSA)</a>.</p><h3 id="đe-tnthpt-tren-he-thong-co-3-phan-tn-đung-sai-tra-loi-ngan" tabindex="-1">Đề TNTHPT trên hệ thống có 3 phần (TN/Đúng-Sai/Trả lời ngắn)? <a class="header-anchor" href="#đe-tnthpt-tren-he-thong-co-3-phan-tn-đung-sai-tra-loi-ngan" aria-label="Permalink to “Đề TNTHPT trên hệ thống có 3 phần (TN/Đúng-Sai/Trả lời ngắn)?”">​</a></h3><p>Có, bám theo đề minh họa mới nhất của Bộ GD&amp;ĐT. Xem <a href="/hoc-vien/thi-tnthpt">Thi thử Tốt nghiệp THPT</a>.</p><h3 id="toi-nen-lam-thi-thu-bao-nhieu-lan-truoc-ky-thi-that" tabindex="-1">Tôi nên làm thi thử bao nhiêu lần trước kỳ thi thật? <a class="header-anchor" href="#toi-nen-lam-thi-thu-bao-nhieu-lan-truoc-ky-thi-that" aria-label="Permalink to “Tôi nên làm thi thử bao nhiêu lần trước kỳ thi thật?”">​</a></h3><ul><li>Trước 3 tháng: 1 đề/tuần.</li><li>Trước 1 tháng: 2-3 đề/tuần.</li><li>Mỗi đề kèm xem lại + ôn câu sai.</li></ul><h2 id="vi-hoi-đap-voi-giao-vien" tabindex="-1">VI. Hỏi đáp với giáo viên <a class="header-anchor" href="#vi-hoi-đap-voi-giao-vien" aria-label="Permalink to “VI. Hỏi đáp với giáo viên”">​</a></h2><h3 id="bao-lau-giao-vien-tra-loi" tabindex="-1">Bao lâu giáo viên trả lời? <a class="header-anchor" href="#bao-lau-giao-vien-tra-loi" aria-label="Permalink to “Bao lâu giáo viên trả lời?”">​</a></h3><p>Thường <strong>trong 24 giờ làm việc</strong>. Nếu quá lâu, đặt câu hỏi nhắc nhẹ hoặc báo trung tâm.</p><h3 id="cau-hoi-cua-toi-co-cong-khai-khong" tabindex="-1">Câu hỏi của tôi có công khai không? <a class="header-anchor" href="#cau-hoi-cua-toi-co-cong-khai-khong" aria-label="Permalink to “Câu hỏi của tôi có công khai không?”">​</a></h3><p>Tùy vị trí hỏi - một số là công khai (khu thảo luận khóa), một số là riêng. Xem <a href="/hoc-vien/hoi-dap">Hỏi đáp</a>.</p><h2 id="vii-giao-vien" tabindex="-1">VII. Giáo viên <a class="header-anchor" href="#vii-giao-vien" aria-label="Permalink to “VII. Giáo viên”">​</a></h2><h3 id="toi-la-giao-vien-lam-sao-co-tai-khoan" tabindex="-1">Tôi là giáo viên, làm sao có tài khoản? <a class="header-anchor" href="#toi-la-giao-vien-lam-sao-co-tai-khoan" aria-label="Permalink to “Tôi là giáo viên, làm sao có tài khoản?”">​</a></h3><p>Admin tạo và cấp cho bạn. Sau đó đăng nhập tại <code>https://lamsonedutech.vn/auth/giaovien</code>. Xem <a href="/giao-vien/">Hướng dẫn Giáo viên</a>.</p><h3 id="toi-quen-mat-khau-giao-vien" tabindex="-1">Tôi quên mật khẩu giáo viên? <a class="header-anchor" href="#toi-quen-mat-khau-giao-vien" aria-label="Permalink to “Tôi quên mật khẩu giáo viên?”">​</a></h3><p>Liên hệ Admin để <strong>Reset mật khẩu</strong>.</p><h3 id="toi-co-the-tao-khoa-hoc-moi-khong" tabindex="-1">Tôi có thể tạo khóa học mới không? <a class="header-anchor" href="#toi-co-the-tao-khoa-hoc-moi-khong" aria-label="Permalink to “Tôi có thể tạo khóa học mới không?”">​</a></h3><p>Tùy quyền Admin cấp. Một số hệ thống chỉ Admin tạo khóa rồi giao giáo viên phụ trách. Xem <a href="/giao-vien/quan-ly-khoa-hoc">Quản lý khóa học</a>.</p><h3 id="hoc-vien-bao-điem-sai-lam-sao" tabindex="-1">Học viên báo điểm sai, làm sao? <a class="header-anchor" href="#hoc-vien-bao-điem-sai-lam-sao" aria-label="Permalink to “Học viên báo điểm sai, làm sao?”">​</a></h3><p>Vào <a href="/giao-vien/quan-ly-diem-thi">Quản lý điểm thi</a> → mở chi tiết bài → đối chiếu → sửa điểm thủ công nếu thật sự sai.</p><h2 id="viii-quan-tri-vien" tabindex="-1">VIII. Quản trị viên <a class="header-anchor" href="#viii-quan-tri-vien" aria-label="Permalink to “VIII. Quản trị viên”">​</a></h2><h3 id="cau-hinh-he-thong-lan-đau-nen-bat-đau-tu-đau" tabindex="-1">Cấu hình hệ thống lần đầu nên bắt đầu từ đâu? <a class="header-anchor" href="#cau-hinh-he-thong-lan-đau-nen-bat-đau-tu-đau" aria-label="Permalink to “Cấu hình hệ thống lần đầu nên bắt đầu từ đâu?”">​</a></h3><p>Theo trình tự: Hệ thống → Phân quyền → Nhân viên → Giáo viên → Khung chương trình → Khóa học → Đề thi → Kinh doanh → Banner. Xem <a href="/admin/">Hướng dẫn Admin</a>.</p><h3 id="cap-quyen-cho-nhan-vien-the-nao" tabindex="-1">Cấp quyền cho nhân viên thế nào? <a class="header-anchor" href="#cap-quyen-cho-nhan-vien-the-nao" aria-label="Permalink to “Cấp quyền cho nhân viên thế nào?”">​</a></h3><p>Tạo <strong>Chức vụ</strong> trong <a href="/admin/phan-quyen">Phân quyền</a> → tick các quyền → gán cho nhân viên.</p><h3 id="xoa-khoa-hoc-co-anh-huong-hoc-vien-khong" tabindex="-1">Xóa khóa học có ảnh hưởng học viên không? <a class="header-anchor" href="#xoa-khoa-hoc-co-anh-huong-hoc-vien-khong" aria-label="Permalink to “Xóa khóa học có ảnh hưởng học viên không?”">​</a></h3><p><strong>Có</strong>, mất tiến độ học. Khuyến nghị <strong>Ẩn thay vì Xóa</strong>. Xem <a href="/admin/khoa-hoc">Khóa học (Admin)</a>.</p><h3 id="toi-muon-backup-du-lieu-truoc-khi-sua-lon" tabindex="-1">Tôi muốn backup dữ liệu trước khi sửa lớn? <a class="header-anchor" href="#toi-muon-backup-du-lieu-truoc-khi-sua-lon" aria-label="Permalink to “Tôi muốn backup dữ liệu trước khi sửa lớn?”">​</a></h3><p>Liên hệ IT/đội kỹ thuật.</p><h2 id="ix-loi-ky-thuat-chung" tabindex="-1">IX. Lỗi kỹ thuật chung <a class="header-anchor" href="#ix-loi-ky-thuat-chung" aria-label="Permalink to “IX. Lỗi kỹ thuật chung”">​</a></h2><h3 id="trang-trang-khong-load" tabindex="-1">Trang trắng / không load? <a class="header-anchor" href="#trang-trang-khong-load" aria-label="Permalink to “Trang trắng / không load?”">​</a></h3><ul><li>Reload (Ctrl+F5).</li><li>Xóa cache trình duyệt.</li><li>Thử trình duyệt khác.</li><li>Thử mạng khác (Wi-Fi → 4G).</li></ul><h3 id="toi-nhan-thong-bao-phien-đang-nhap-đa-het-han" tabindex="-1">Tôi nhận thông báo &quot;Phiên đăng nhập đã hết hạn&quot;? <a class="header-anchor" href="#toi-nhan-thong-bao-phien-đang-nhap-đa-het-han" aria-label="Permalink to “Tôi nhận thông báo &quot;Phiên đăng nhập đã hết hạn&quot;?”">​</a></h3><p>Đăng nhập lại. Nếu xảy ra liên tục, kiểm tra ngày giờ máy có đúng không.</p><h3 id="he-thong-cham-vao-gio-cao-điem" tabindex="-1">Hệ thống chậm vào giờ cao điểm? <a class="header-anchor" href="#he-thong-cham-vao-gio-cao-điem" aria-label="Permalink to “Hệ thống chậm vào giờ cao điểm?”">​</a></h3><p>Có thể do nhiều người cùng truy cập (đặc biệt khi có đợt thi thử). Thử lại sau vài phút.</p><h3 id="toi-muon-bao-loi-moi" tabindex="-1">Tôi muốn báo lỗi mới? <a class="header-anchor" href="#toi-muon-bao-loi-moi" aria-label="Permalink to “Tôi muốn báo lỗi mới?”">​</a></h3><p>Mô tả chi tiết: bạn đang làm gì, trang nào (URL), mong đợi gì, lỗi gì xuất hiện. Chụp ảnh màn hình. Gửi qua <strong>Hỏi đáp</strong> hoặc hotline trung tâm.</p><h2 id="van-can-ho-tro" tabindex="-1">Vẫn cần hỗ trợ? <a class="header-anchor" href="#van-can-ho-tro" aria-label="Permalink to “Vẫn cần hỗ trợ?”">​</a></h2><ul><li>📞 Hotline: xem footer trang</li><li>📧 Email: xem footer trang</li><li>💬 Zalo / Messenger: xem footer trang</li><li>🆘 Sử dụng <a href="/hoc-vien/hoi-dap">Hỏi đáp</a> ngay trong hệ thống</li></ul><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Khi liên hệ hỗ trợ, hãy cung cấp:</p><ul><li>Tên tài khoản (SĐT/email)</li><li>Mã hóa đơn (nếu liên quan thanh toán)</li><li>Tên khóa/đề (nếu liên quan học/thi)</li><li>Ảnh chụp lỗi (nếu có)</li></ul></div>',97)])])}const s=h(o,[["render",l]]);export{k as __pageData,s as default};
